module bin2gray_4bit(
    input [3:0] _reverse_bin, 
    output [3:0] gray);

    assign gray[3] = _reverse_bin[3];
    assign gray[2] = _reverse_bin[3] ^ _reverse_bin[2];
    assign gray[1] = _reverse_bin[2] ^ _reverse_bin[1];
    assign gray[0] = _reverse_bin[1] ^ _reverse_bin[0];
endmodule
